  # Renderira inline SVG za podano ime ikone. Vrne nil, če ime ni v naboru (graceful —
  # napačno/zastarelo besedilo v bazi ne podre strani, ikona se preprosto ne prikaže).
  def icon_svg(name, css_class: "h-5 w-5", aria_hidden: true)
    path = ICONS[name.to_s]
    return nil if path.blank?

    content_tag(:svg, class: css_class, fill: "none", viewBox: "0 0 24 24",
                "stroke-width": "1.5", stroke: "currentColor",
                aria: aria_hidden ? { hidden: "true" } : {}) do
      tag.path(stroke_linecap: "round", stroke_linejoin: "round", d: path)
    end
  end

  # Seznam (ime, ime) parov za uporabo v `f.select` admin obrazcu — vrstni red kot v ICONS.
  def icon_select_options
    ICONS.keys.map { |name| [name.tr("-", " ").capitalize, name] }
  end
end
